<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Ubuntu Desktop</title>
  <style>
    :root {
      --bg: #151923;
      --panel: #222735;
      --panel-dark: #1b1f2a;
      --border: #3b4355;
      --text: #edf1f7;
      --muted: #9da7b8;
      --accent: #e95420;
      --accent-light: #ff7b4d;
      --blue: #4f8cff;
      --shadow: 0 22px 55px rgba(0,0,0,.45);
    }

    * { box-sizing: border-box; }

    html, body {
      width: 100%;
      height: 100%;
      margin: 0;
      overflow: hidden;
      font-family: Arial, Helvetica, sans-serif;
      color: var(--text);
      background: #10131a;
    }

    button, textarea { font: inherit; }

    #desktop {
      position: relative;
      width: 100vw;
      height: 100vh;
      min-height: 500px;
      overflow: hidden;
      background:
        radial-gradient(circle at 78% 24%, rgba(102, 62, 113, .35), transparent 28%),
        radial-gradient(circle at 18% 80%, rgba(29, 83, 119, .3), transparent 32%),
        linear-gradient(135deg, #182536 0%, #25203b 48%, #141923 100%);
    }

    #desktop::before {
      content: "";
      position: absolute;
      inset: 42px 0 65px;
      opacity: .25;
      background:
        linear-gradient(125deg, transparent 0 38%, rgba(255,255,255,.06) 38.2% 38.6%, transparent 39%),
        linear-gradient(35deg, transparent 0 61%, rgba(255,255,255,.045) 61.2% 61.5%, transparent 62%);
      pointer-events: none;
    }

    #topbar {
      height: 42px;
      position: relative;
      z-index: 20;
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0 17px;
      background: rgba(20, 23, 31, .92);
      border-bottom: 1px solid rgba(255,255,255,.08);
      font-size: 13px;
    }

    .top-left, .top-right {
      display: flex;
      align-items: center;
      gap: 17px;
    }

    .brand {
      font-weight: bold;
      letter-spacing: .2px;
    }

    .brand-mark {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      width: 23px;
      height: 23px;
      margin-right: 7px;
      border-radius: 50%;
      background: var(--accent);
      color: white;
      font-size: 12px;
    }

    .system-icon { color: #cbd3df; }
    .clock { color: #d8dee8; }

    .window {
      position: absolute;
      z-index: 5;
      display: none;
      flex-direction: column;
      width: 720px;
      height: 470px;
      min-width: 360px;
      min-height: 240px;
      max-width: calc(100vw - 28px);
      max-height: calc(100vh - 125px);
      overflow: hidden;
      background: var(--panel);
      border: 1px solid rgba(255,255,255,.14);
      border-radius: 9px;
      box-shadow: var(--shadow);
    }

    .window.open { display: flex; }

    #files-window { left: 9%; top: 11%; }
    #notepad-window { left: 19%; top: 15%; }

    .titlebar {
      height: 42px;
      flex: 0 0 42px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0 12px 0 16px;
      background: #292e3b;
      border-bottom: 1px solid var(--border);
      cursor: grab;
      user-select: none;
    }

    .titlebar:active { cursor: grabbing; }

    .window-title {
      display: flex;
      gap: 9px;
      align-items: center;
      font-size: 14px;
      font-weight: bold;
    }

    .app-symbol {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      width: 21px;
      height: 21px;
      border-radius: 5px;
      background: var(--accent);
      color: white;
      font-size: 12px;
    }

    .win-close {
      width: 27px;
      height: 27px;
      padding: 0;
      border: 0;
      border-radius: 50%;
      color: #e7ebf2;
      background: transparent;
      cursor: pointer;
      font-size: 19px;
      line-height: 25px;
    }

    .win-close:hover { background: #e95420; }

    .files-toolbar {
      display: flex;
      align-items: center;
      gap: 10px;
      padding: 10px 13px;
      border-bottom: 1px solid var(--border);
      background: #202530;
    }

    #files-up, #new-tab {
      border: 1px solid #495368;
      border-radius: 5px;
      background: #303747;
      color: var(--text);
      cursor: pointer;
    }

    #files-up {
      width: 34px;
      height: 29px;
      font-size: 18px;
    }

    #files-up:hover, #new-tab:hover { background: #404b61; }

    #files-up:disabled {
      cursor: default;
      opacity: .42;
    }

    #files-path {
      flex: 1;
      min-width: 0;
      padding: 7px 10px;
      border: 1px solid #3d4658;
      border-radius: 5px;
      color: #dce4f1;
      background: #171b24;
      font-family: monospace;
      font-size: 13px;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }

    #files-list {
      flex: 1;
      overflow: auto;
      padding: 15px;
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(135px, 1fr));
      align-content: start;
      gap: 10px;
      background: #1d222d;
    }

    .fs-item {
      display: flex;
      align-items: center;
      gap: 11px;
      min-height: 58px;
      padding: 10px;
      border: 1px solid transparent;
      border-radius: 7px;
      color: #e8edf5;
      cursor: default;
      overflow: hidden;
    }

    .fs-item:hover {
      background: #2a3242;
      border-color: #455168;
    }

    .fs-icon {
      flex: 0 0 auto;
      font-size: 25px;
    }

    .fs-name {
      min-width: 0;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
      font-size: 13px;
    }

    .notepad-body {
      min-height: 0;
      flex: 1;
      display: flex;
      flex-direction: column;
      background: #171b24;
    }

    #tabs {
      flex: 0 0 auto;
      display: flex;
      align-items: center;
      gap: 3px;
      min-height: 43px;
      padding: 6px 8px 0;
      overflow-x: auto;
      background: #202530;
      border-bottom: 1px solid var(--border);
    }

    .tab {
      flex: 0 0 auto;
      max-width: 180px;
      padding: 9px 16px;
      border: 0;
      border-radius: 6px 6px 0 0;
      color: var(--muted);
      background: transparent;
      cursor: pointer;
      font-size: 13px;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }

    .tab:hover { color: var(--text); background: #2b3240; }

    .tab.active {
      color: white;
      background: #171b24;
      box-shadow: inset 0 2px var(--accent);
    }

    #new-tab {
      flex: 0 0 auto;
      width: 29px;
      height: 28px;
      margin: 0 4px 5px 3px;
      font-size: 19px;
      line-height: 20px;
    }

    #editor {
      flex: 1;
      width: 100%;
      min-height: 150px;
      resize: none;
      padding: 19px 21px;
      border: 0;
      outline: 0;
      color: #e6ebf4;
      background: #171b24;
      font-family: "Courier New", monospace;
      font-size: 14px;
      line-height: 1.65;
      tab-size: 2;
    }

    #taskbar {
      position: absolute;
      z-index: 30;
      left: 50%;
      bottom: 13px;
      transform: translateX(-50%);
      display: flex;
      align-items: center;
      gap: 8px;
      padding: 7px 10px;
      border: 1px solid rgba(255,255,255,.12);
      border-radius: 11px;
      background: rgba(24, 27, 36, .91);
      box-shadow: 0 8px 25px rgba(0,0,0,.3);
      backdrop-filter: blur(10px);
    }

    #taskbar button {
      display: flex;
      align-items: center;
      gap: 8px;
      min-width: 125px;
      height: 38px;
      padding: 0 14px;
      border: 1px solid transparent;
      border-radius: 7px;
      color: #ecf0f7;
      background: transparent;
      cursor: pointer;
      font-size: 13px;
    }

    #taskbar button:hover {
      background: #343d4d;
      border-color: #4b566b;
    }

    .dock-icon {
      display: inline-flex;
      width: 23px;
      height: 23px;
      align-items: center;
      justify-content: center;
      border-radius: 5px;
      background: var(--accent);
      font-size: 14px;
    }

    #open-notepad .dock-icon { background: #5a78bf; }

    @media (max-width: 650px) {
      #taskbar button { min-width: 50px; padding: 0 11px; }
      #taskbar button span:last-child { display: none; }
      #files-window, #notepad-window { left: 14px; top: 65px; }
      .window { width: calc(100vw - 28px); }
    }
  </style>
</head>
<body>
  <main id="desktop">
    <header id="topbar">
      <div class="top-left">
        <span class="brand"><span class="brand-mark">✦</span>Activities</span>
        <span>Ubuntu Desktop</span>
      </div>
      <div class="top-right">
        <span class="system-icon">⌁</span>
        <span class="system-icon">▣</span>
        <span class="system-icon">▰</span>
        <span class="clock" id="clock">12:00</span>
      </div>
    </header>

    <section id="files-window" class="window" aria-label="Files">
      <div class="titlebar">
        <div class="window-title"><span class="app-symbol">▣</span>Files</div>
        <button class="win-close" aria-label="Close Files">×</button>
      </div>
      <div class="files-toolbar">
        <button id="files-up" title="Parent folder" aria-label="Go to parent folder">↑</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-list" aria-label="File listing"></div>
    </section>

    <section id="notepad-window" class="window" aria-label="Notepad">
      <div class="titlebar">
        <div class="window-title"><span class="app-symbol">✎</span>Notepad</div>
        <button class="win-close" aria-label="Close Notepad">×</button>
      </div>
      <div class="notepad-body">
        <div id="tabs"></div>
        <textarea id="editor" spellcheck="false" aria-label="Text editor"></textarea>
      </div>
    </section>

    <nav id="taskbar" aria-label="Application dock">
      <button id="open-files"><span class="dock-icon">▣</span><span>Files</span></button>
      <button id="open-notepad"><span class="dock-icon">✎</span><span>Notepad</span></button>
    </nav>
  </main>

  <script>
    (() => {
      const $ = selector => document.querySelector(selector);

      function directory(entries) {
        return { type: "directory", entries };
      }
      function file() {
        return { type: "file" };
      }

      const filesystem = directory({
        bin: directory({ bash: file(), cat: file(), ls: file(), nano: file() }),
        etc: directory({ hosts: file(), passwd: file(), "os-release": file() }),
        home: directory({
          user: directory({
            Documents: directory({}),
            Downloads: directory({}),
            Pictures: directory({}),
            "welcome.txt": file()
          })
        }),
        usr: directory({
          bin: directory({ python3: file(), node: file() }),
          share: directory({ applications: directory({}) })
        }),
        var: directory({
          log: directory({ "system.log": file(), "app.log": file() }),
          tmp: directory({})
        }),
        opt: directory({}),
        "README.md": file()
      });

      const filesPath = $("#files-path");
      const filesList = $("#files-list");
      const filesUp = $("#files-up");
      let currentPath = [];

      function getDirectory(path) {
        let node = filesystem;
        for (const part of path) {
          if (!node.entries[part] || node.entries[part].type !== "directory") return filesystem;
          node = node.entries[part];
        }
        return node;
      }

      function renderFiles() {
        const current = getDirectory(currentPath);
        filesPath.textContent = "/" + (currentPath.length ? currentPath.join("/") : "");
        filesUp.disabled = currentPath.length === 0;
        filesList.innerHTML = "";

        Object.keys(current.entries).sort((a, b) => {
          const ad = current.entries[a].type === "directory";
          const bd = current.entries[b].type === "directory";
          return ad === bd ? a.localeCompare(b) : (ad ? -1 : 1);
        }).forEach(name => {
          const itemData = current.entries[name];
          const item = document.createElement("div");
          item.className = "fs-item";
          item.dataset.folder = itemData.type === "directory" ? "true" : "false";
          item.title = itemData.type === "directory" ? "Double-click to open folder" : name;

          const icon = document.createElement("span");
          icon.className = "fs-icon";
          icon.textContent = itemData.type === "directory" ? "📁" : "📄";

          const label = document.createElement("span");
          label.className = "fs-name";
          label.textContent = name;

          item.append(icon, label);
          if (itemData.type === "directory") {
            item.addEventListener("dblclick", () => {
              currentPath.push(name);
              renderFiles();
            });
          }
          filesList.appendChild(item);
        });
      }

      filesUp.addEventListener("click", () => {
        if (currentPath.length) {
          currentPath.pop();
          renderFiles();
        }
      });
      renderFiles();

      function showWindow(id) {
        const win = document.getElementById(id);
        win.classList.add("open");
        win.style.zIndex = ++showWindow.layer;
      }
      showWindow.layer = 10;

      $("#open-files").addEventListener("click", () => showWindow("files-window"));
      $("#open-notepad").addEventListener("click", () => {
        showWindow("notepad-window");
        $("#editor").focus();
      });

      document.querySelectorAll(".window").forEach(win => {
        win.addEventListener("pointerdown", () => win.style.zIndex = ++showWindow.layer);
        win.querySelector(".win-close").addEventListener("click", () => {
          win.classList.remove("open");
        });
      });

      document.querySelectorAll(".titlebar").forEach(bar => {
        bar.addEventListener("pointerdown", event => {
          if (event.target.closest("button")) return;
          const win = bar.closest(".window");
          const rect = win.getBoundingClientRect();
          const startX = event.clientX;
          const startY = event.clientY;
          const startLeft = rect.left;
          const startTop = rect.top;
          win.setPointerCapture(event.pointerId);

          const move = e => {
            const maxLeft = Math.max(8, window.innerWidth - win.offsetWidth - 8);
            const maxTop = Math.max(48, window.innerHeight - win.offsetHeight - 75);
            win.style.left = Math.min(maxLeft, Math.max(8, startLeft + e.clientX - startX)) + "px";
            win.style.top = Math.min(maxTop, Math.max(48, startTop + e.clientY - startY)) + "px";
          };
          const stop = () => {
            win.removeEventListener("pointermove", move);
            win.removeEventListener("pointerup", stop);
            win.removeEventListener("pointercancel", stop);
          };
          win.addEventListener("pointermove", move);
          win.addEventListener("pointerup", stop);
          win.addEventListener("pointercancel", stop);
        });
      });

      const storageKey = "ubuntu-desktop-notepad-tabs-v1";
      let noteState;
      try {
        noteState = JSON.parse(localStorage.getItem(storageKey) || "null");
      } catch (e) {
        noteState = null;
      }

      if (!noteState || !Array.isArray(noteState.tabs) || !noteState.tabs.length) {
        noteState = {
          active: "tab-1",
          tabs: [{ id: "tab-1", title: "Untitled 1", content: "" }]
        };
      }

      let tabCounter = noteState.tabs.reduce((max, tab) => {
        const match = String(tab.title).match(/\d+/);
        return Math.max(max, match ? Number(match[0]) : 0);
      }, noteState.tabs.length);

      function saveNotes() {
        localStorage.setItem(storageKey, JSON.stringify(noteState));
      }

      function renderTabs() {
        const tabs = $("#tabs");
        tabs.innerHTML = "";
        noteState.tabs.forEach(tabData => {
          const tab = document.createElement("button");
          tab.className = "tab" + (tabData.id === noteState.active ? " active" : "");
          tab.textContent = tabData.title;
          tab.title = tabData.title;
          tab.addEventListener("click", () => {
            noteState.active = tabData.id;
            renderTabs();
            saveNotes();
          });
          tabs.appendChild(tab);
        });

        const newTab = document.createElement("button");
        newTab.id = "new-tab";
        newTab.textContent = "+";
        newTab.title = "New tab";
        newTab.addEventListener("click", () => {
          tabCounter++;
          const tabData = {
            id: "tab-" + Date.now() + "-" + tabCounter,
            title: "Untitled " + tabCounter,
            content: ""
          };
          noteState.tabs.push(tabData);
          noteState.active = tabData.id;
          renderTabs();
          renderEditor();
          saveNotes();
          $("#editor").focus();
        });
        tabs.appendChild(newTab);
      }

      function renderEditor() {
        const active = noteState.tabs.find(tab => tab.id === noteState.active) || noteState.tabs[0];
        noteState.active = active.id;
        $("#editor").value = active.content;
      }

      $("#editor").addEventListener("input", event => {
        const active = noteState.tabs.find(tab => tab.id === noteState.active);
        if (active) {
          active.content = event.target.value;
          saveNotes();
        }
      });

      renderTabs();
      renderEditor();
      saveNotes();

      function updateClock() {
        const now = new Date();
        $("#clock").textContent = now.toLocaleTimeString([], {
          hour: "2-digit",
          minute: "2-digit"
        });
      }
      updateClock();
      setInterval(updateClock, 30000);
    })();
  </script>
</body>
</html>
